// Tuple sintaksisi
let person: [string, number] = ['Ali', 25];

console.log(person); // ['Ali', 25]
console.log(person[0]); // Ali
console.log(person[1]); // 25
// person = ['Vəli', 30, true]; // Xəta: tuple yalnız iki element qəbul edir
// person[0] = 42; // Xəta: number string-ə təyin edilə bilməz

// Tuple vs adi massiv
let tuple: [string, number] = ['Test', 42];
let array: string[] = ['Test', 'Hello'];

console.log(tuple); // ['Test', 42]
console.log(array); // ['Test', 'Hello']
// tuple.push('Extra'); // Xəta: tuple-lar sabit uzunluqludur
array.push('World'); // OK: adi massivlər çevikdir

// Readonly tuple
let readOnlyTuple: readonly [string, number] = ['Ali', 25];

console.log(readOnlyTuple); // ['Ali', 25]
// readOnlyTuple[0] = 'Vəli'; // Xəta: readonly tuple dəyişdirilə bilməz
// readOnlyTuple.push('Extra'); // Xəta: readonly tuple-a əlavə etmək olmur

// Opsional elementlər
let optionalTuple: [string, number, boolean?] = ['Ali', 25];

console.log(optionalTuple); // ['Ali', 25]
optionalTuple = ['Vəli', 30, true]; // OK
console.log(optionalTuple); // ['Vəli', 30, true]
// optionalTuple = ['Ayşə', 35, 'test']; // Xəta: string boolean-a təyin edilə bilməz

// Rest elementləri
let restTuple: [string, ...number[]] = ['Test', 1, 2, 3];

console.log(restTuple); // ['Test', 1, 2, 3]
restTuple = ['Demo', 4]; // OK
// restTuple = ['Demo', 'Extra']; // Xəta: string number-a təyin edilə bilməz

// Tuple vs obyekt
let tuple: [string, number] = ['Ali', 25];
let object: { name: string; age: number } = { name: 'Ali', age: 25 };

console.log(tuple[0]); // Ali
console.log(object.name); // Ali

// Praktik nümunə
function getCoordinates(): [number, number] {
  return [40.7128, -74.0060]; // New York koordinatları
}

let coords: [number, number] = getCoordinates();
console.log(`En: ${coords[0]}, Uzunluq: ${coords[1]}`);
// Çıxış: En: 40.7128, Uzunluq: -74.0060

// Təhlükəsizlik nümunəsi
let tuple: [string, number] = ['Test', 42];

if (typeof tuple[0] === 'string') {
  console.log(tuple[0].toUpperCase()); // TEST
}
// tuple = [42, 'Error']; // Xəta: tip və ya sıra uyğun deyil

// Səhvə yol açan nümunə
let unsafe: any = ['Hello', 42];
unsafe.push(true); // Təhlükəsiz deyil, runtime səhvi ola bilər
console.log(unsafe); // ['Hello', 42, true]

// Düzgün yol
let safe: [string, number] = ['Hello', 42];
console.log(safe); // ['Hello', 42]
// safe.push('Extra'); // Xəta: tuple-a əlavə etmək olmur

// Real layihə ssenarisi
function getRGB(): [number, number, number] {
  return [255, 128, 0]; // Narıncı rəng
}

let color: [number, number, number] = getRGB();
console.log(`R: ${color[0]}, G: ${color[1]}, B: ${color[2]}`);
// Çıxış: R: 255, G: 128, B: 0

