// Tuple syntax
let person: [string, number] = ['Alice', 25];

console.log(person); // ['Alice', 25]
console.log(person[0]); // Alice
console.log(person[1]); // 25
// person = ['Bob', 30, true]; // Error: tuple expects only two elements
// person[0] = 42; // Error: number cannot be assigned to string

// Tuple vs regular array
let tuple: [string, number] = ['Test', 42];
let array: string[] = ['Test', 'Hello'];

console.log(tuple); // ['Test', 42]
console.log(array); // ['Test', 'Hello']
// tuple.push('Extra'); // Error: tuples have fixed length
array.push('World'); // OK: regular arrays are flexible

// Readonly tuple
let readOnlyTuple: readonly [string, number] = ['Alice', 25];

console.log(readOnlyTuple); // ['Alice', 25]
// readOnlyTuple[0] = 'Bob'; // Error: cannot modify readonly tuple
// readOnlyTuple.push('Extra'); // Error: cannot push to readonly tuple

// Optional elements
let optionalTuple: [string, number, boolean?] = ['Alice', 25];

console.log(optionalTuple); // ['Alice', 25]
optionalTuple = ['Bob', 30, true]; // OK
console.log(optionalTuple); // ['Bob', 30, true]
// optionalTuple = ['Eve', 35, 'test']; // Error: string cannot be assigned to boolean

// Rest elements
let restTuple: [string, ...number[]] = ['Test', 1, 2, 3];

console.log(restTuple); // ['Test', 1, 2, 3]
restTuple = ['Demo', 4]; // OK
// restTuple = ['Demo', 'Extra']; // Error: string cannot be assigned to number

// Tuple vs object
let tuple: [string, number] = ['Alice', 25];
let object: { name: string; age: number } = { name: 'Alice', age: 25 };

console.log(tuple[0]); // Alice
console.log(object.name); // Alice

// Practical example
function getCoordinates(): [number, number] {
  return [40.7128, -74.0060]; // New York coordinates
}

let coords: [number, number] = getCoordinates();
console.log(`Latitude: ${coords[0]}, Longitude: ${coords[1]}`);
// Output: Latitude: 40.7128, Longitude: -74.0060

// Security example
let tuple: [string, number] = ['Test', 42];

if (typeof tuple[0] === 'string') {
  console.log(tuple[0].toUpperCase()); // TEST
}
// tuple = [42, 'Error']; // Error: type or order mismatch

// Error-prone example
let unsafe: any = ['Hello', 42];
unsafe.push(true); // Unsafe, may cause runtime errors
console.log(unsafe); // ['Hello', 42, true]

// Correct approach
let safe: [string, number] = ['Hello', 42];
console.log(safe); // ['Hello', 42]
// safe.push('Extra'); // Error: cannot push to tuple

// Real-world scenario
function getRGB(): [number, number, number] {
  return [255, 128, 0]; // Orange color
}

let color: [number, number, number] = getRGB();
console.log(`R: ${color[0]}, G: ${color[1]}, B: ${color[2]}`);
// Output: R: 255, G: 128, B: 0

