// Синтаксис кортежей
let person: [string, number] = ['Алиса', 25];

console.log(person); // ['Алиса', 25]
console.log(person[0]); // Алиса
console.log(person[1]); // 25
// person = ['Боб', 30, true]; // Ошибка: кортеж ожидает только два элемента
// person[0] = 42; // Ошибка: number не может быть присвоен string

// Кортеж vs обычный массив
let tuple: [string, number] = ['Тест', 42];
let array: string[] = ['Тест', 'Привет'];

console.log(tuple); // ['Тест', 42]
console.log(array); // ['Тест', 'Привет']
// tuple.push('Экстра'); // Ошибка: кортежи имеют фиксированную длину
array.push('Мир'); // OK: обычные массивы гибкие

// Кортеж только для чтения
let readOnlyTuple: readonly [string, number] = ['Алиса', 25];

console.log(readOnlyTuple); // ['Алиса', 25]
// readOnlyTuple[0] = 'Боб'; // Ошибка: нельзя изменить кортеж только для чтения
// readOnlyTuple.push('Экстра'); // Ошибка: нельзя добавить в кортеж только для чтения

// Необязательные элементы
let optionalTuple: [string, number, boolean?] = ['Алиса', 25];

console.log(optionalTuple); // ['Алиса', 25]
optionalTuple = ['Боб', 30, true]; // OK
console.log(optionalTuple); // ['Боб', 30, true]
// optionalTuple = ['Ева', 35, 'тест']; // Ошибка: string не может быть присвоен boolean

// Rest-элементы
let restTuple: [string, ...number[]] = ['Тест', 1, 2, 3];

console.log(restTuple); // ['Тест', 1, 2, 3]
restTuple = ['Демо', 4]; // OK
// restTuple = ['Демо', 'Экстра']; // Ошибка: string не может быть присвоен number

// Кортеж vs объект
let tuple: [string, number] = ['Алиса', 25];
let object: { name: string; age: number } = { name: 'Алиса', age: 25 };

console.log(tuple[0]); // Алиса
console.log(object.name); // Алиса

// Практический пример
function getCoordinates(): [number, number] {
  return [40.7128, -74.0060]; // Координаты Нью-Йорка
}

let coords: [number, number] = getCoordinates();
console.log(`Широта: ${coords[0]}, Долгота: ${coords[1]}`);
// Вывод: Широта: 40.7128, Долгота: -74.0060

// Пример безопасности
let tuple: [string, number] = ['Тест', 42];

if (typeof tuple[0] === 'string') {
  console.log(tuple[0].toUpperCase()); // ТЕСТ
}
// tuple = [42, 'Ошибка']; // Ошибка: несоответствие типа или порядка

// Пример, вызывающий ошибку
let unsafe: any = ['Привет', 42];
unsafe.push(true); // Небезопасно, может вызвать ошибки во время выполнения
console.log(unsafe); // ['Привет', 42, true]

// Правильный подход
let safe: [string, number] = ['Привет', 42];
console.log(safe); // ['Привет', 42]
// safe.push('Экстра'); // Ошибка: нельзя добавить в кортеж

// Реальный сценарий
function getRGB(): [number, number, number] {
  return [255, 128, 0]; // Оранжевый цвет
}

let color: [number, number, number] = getRGB();
console.log(`R: ${color[0]}, G: ${color[1]}, B: ${color[2]}`);
// Вывод: R: 255, G: 128, B: 0

